{"keystrokes": "python3 -c "
import solution

# Test with different PWMs
pwm1 = {
    'A': [10, 0, 0, 0],
    'C': [0, 10, 0, 0],
    'G': [0, 0, 10, 0],
    'T': [0, 0, 0, 10]
}

pwm2 = {
    'A': [8, 1, 2, 1],
    'C': [1, 7, 1, 2],
    'G': [1, 1, 6, 1],
    'T': [2, 3, 3, 8]
}

for name, pwm in [('Deterministic', pwm1), ('Variable', pwm2)]:
    correct = 0
    total = 20
    for _ in range(total):
        p, seq, seq_rc = solution.generate_dna(100, pwm)
        detected = solution.scan_sequence(seq, pwm, 0.8, 100)
        if detected == p:
            correct += 1
    print(f'{name}: {correct}/{total} = {correct/total*100:.1f}%')
"
", "duration": 15.0}

